Section: Cable name / Description
Table data:
{
  "page": 18,
  "table_index": 1,
  "headers": [
    "Cable name",
    "Description"
  ],
  "rows": [
    {
      "Cable name": "DVI to HDMI",
      "Description": "DVI to HDMI cables can transmit only digital video signals and not audio signals. Werecommend that you use HDMI to HDMI cables."
    },
    {
      "Cable name": "Optical",
      "Description": "Optical cables are used to transmit audio signals to external speakers with low signal loss. Optical cables can't transmit video signals."
    },
    {
      "Cable name": "Component",
      "Description": "Component cables transmit analogue signals. The video signal is separated and transmitted to the red, green, and blue terminals to provide HD (1080i) pictures. The audio signal is transmitted to the red and white terminals."
    },
    {
      "Cable name": "Composite",
      "Description": "Composite cables transmit analogue signals. The video signal is transmitted to the yellow terminal, and the audio signal is transmitted to the red and white terminals."
    }
  ],
  "source": "docling"
}

Section: Button / Description
Table data:
{
  "page": 29,
  "table_index": 4,
  "headers": [
    "Button",
    "Description"
  ],
  "rows": [
    {
      "Button": "(Play/pause)",
      "Description": "When pressed, the playback controls appear. Using these controls, you can control the media content that is playing. To use Game Bar, press and hold the button in Game Mode . Game Bar may not be supported depending on the model or geographical area."
    },
    {
      "Button": "(Volume)",
      "Description": "Move the button up or down to adjust the volume. To mute the sound, press the button. When pressed for 2 seconds or more, the Accessibility Shortcuts appears. may not be present, depending on the model."
    },
    {
      "Button": "(Channel)",
      "Description": "Move the button up or down to change the channel. To see the Guide screen, press the button. When pressed for 1 second or more, the Channel List screen appears. Press and hold the button up or down to quickly change the channel."
    },
    {
      "Button": "Launch app button",
      "Description": "Launch the app indicated by the button. Available apps may differ depending on the geographical area or contents provider. This function may not be supported depending on the model."
    }
  ],
  "source": "docling"
}

