  ],
  "rows": [
    {
      "Function": "Slideshow Speed",
      "Description": "Sets the slideshow speed. If there is only one image file in the USB device, the slide show is not played."
    },
    {
      "Function": "Slideshow Effect",
      "Description": "Applies transition effects to the slide show. If there is only one image file in the USB device, the slide show is not played."
    },
    {
      "Function": "Background Music",
      "Description": "Plays background music as you set in the pop-up window while the TV displays photos. The music files must be saved in the same USB device as the photo files. To pause the background music, select Background Music on the playback screen bottom."
    },
    {
      "Function": "Subtitles",
      "Description": "You can set the detailed subtitle options, such as the language, sync, size, and color. If subtitles are not displayed correctly, check the encoding setting."
    },
    {
      "Function": "Rotate",
      "Description": "Rotates the video."
    },
    {
      "Function": "Audio Language",
      "Description": "Changes the audio language. This function is only available if the video supports multi-track sound."
    },
    {
      "Function": "Information",
      "Description": "Displays detailed information about the current multimedia content."
    }
  ],
  "source": "docling"
